import{_ as a,o as i,c as e,ai as n}from"./chunks/framework.Cz-NuZmh.js";const c=JSON.parse('{"title":"AWS Bedrock","description":"","frontmatter":{},"headers":[],"relativePath":"providers/bedrock.md","filePath":"providers/bedrock.md","rawMarkdown":"# AWS Bedrock\\n\\n**Provider value:** `bedrock`\\n\\n## Setup\\n\\n**Option 1: AWS credential chain** (recommended)\\n\\nra uses the standard AWS credential chain:\\n\\n1. `AWS_ACCESS_KEY_ID` / `AWS_SECRET_ACCESS_KEY` env vars\\n2. `~/.aws/credentials` file\\n3. IAM instance roles\\n\\n```bash\\nexport AWS_ACCESS_KEY_ID=...\\nexport AWS_SECRET_ACCESS_KEY=...\\nexport AWS_REGION=us-east-1\\nra --provider bedrock \\"Hello\\"\\n```\\n\\n**Option 2: Bearer token**\\n\\nA bearer token can be set in a config file:\\n\\n```yaml\\napp:\\n  providers:\\n    bedrock:\\n      apiKey: your-bearer-token\\n```\\n\\n```bash\\nexport AWS_REGION=us-east-1\\nra --provider bedrock \\"Hello\\"\\n```\\n\\n## Custom endpoint\\n\\nUse `baseURL` to point at a custom or proxy endpoint (e.g. a VPC endpoint, LocalStack, or a Bedrock-compatible gateway):\\n\\n```yaml\\napp:\\n  providers:\\n    bedrock:\\n      baseURL: https://vpce-abc123.bedrock-runtime.us-east-1.vpce.amazonaws.com\\n```\\n\\nOr via CLI flag:\\n\\n```bash\\nra --provider bedrock --bedrock-base-url https://vpce-abc123.bedrock-runtime.us-east-1.vpce.amazonaws.com \\"Hello\\"\\n```\\n\\n## Environment variables\\n\\n| Variable | Required | Description |\\n|----------|----------|-------------|\\n| `AWS_REGION` | Yes | AWS region (e.g. `us-east-1`) |\\n\\n## Models\\n\\nUse the full Bedrock model ID:\\n\\n```bash\\nra --provider bedrock --model anthropic.claude-sonnet-4-6 \\"Triage this bug\\"\\n```\\n\\n## Extended thinking\\n\\nSupported modes: `off`, `low`, `medium`, `high`, `adaptive`.\\n\\n```bash\\nra --provider bedrock --thinking medium \\"Analyze this architecture\\"\\n```\\n\\n## See also\\n\\n- [Context Control](/core/context-control) — extended thinking details\\n- [Configuration](/configuration/) — provider credentials reference\\n"}'),t={name:"providers/bedrock.md"};function l(r,s,o,p,h,d){return i(),e("div",null,[...s[0]||(s[0]=[n("",26)])])}const g=a(t,[["render",l]]);export{c as __pageData,g as default};
